module RefModule(
  input [7:0] A,
  input [7:0] B,
  output reg [7:0] sum,
  output reg carry
);reg [8:0] obf_temp_sum;

  always @ (A or B) begin
    obf_temp_sum = A + B;
    if (obf_temp_sum > 255) begin
      carry = 1;
      sum = obf_temp_sum[7:0];
    end else begin
      carry = 0;
      sum = obf_temp_sum[7:0];
    end
  end

endmodule
